Hi! This is my code for send vibration in gamepad in python (works with xbox 360 controller, dualshock 4, wii remote).
`import fcntl, struct, array, time
	
EVIOCRMFF = 0x40044581
EVIOCSFF = 0x40304580
LOG_CLASS_ON = False
TIME_DELTA = 250

class Vibrate:

    def __init__(self, file):
        self.ff_joy = open(file, "r+")

    def close(self):
        self.ff_joy.close()

    def new_effect(self, strong, weak, length):
        effect = struct.pack('HhHHHHHxHH', 0x50, -1, 0, 0, 0, length, 0, int(strong * 0xFFFF), int(weak * 0xFFFF))
        a = array.array('h', effect)
        fcntl.ioctl(self.ff_joy, EVIOCSFF, a, True)
        return a[1]
        id = a[1]
        return (ev_play, ev_stop)

    def play_efect(self, id):
        if type(id) == tuple or type(id) == list:
            ev_play = ''
            for i in id:
                ev_play = ev_play + struct.pack('LLHHi', 0, 0, 0x15, i, 1)
        else:
            ev_play = struct.pack('LLHHi', 0, 0, 0x15, id, 1)
        self.ff_joy.write(ev_play)
        self.ff_joy.flush()

    def stop_effect(self, id):
        if type(id) == tuple or type(id) == list:
            ev_stop = ''
            for i in id:
                ev_stop = ev_stop + struct.pack('LLHHi', 0, 0, 0x15, i, 0)
        else:
            ev_stop = struct.pack('LLHHi', 0, 0, 0x15, id, 0)
        self.ff_joy.write(ev_stop)
        self.ff_joy.flush()

    def forget_effect(self, id):
        if type(id) == tuple or type(id) == list:
            for i in id:
                fcntl.ioctl(self.ff_joy, EVIOCRMFF, i)
        else:
            fcntl.ioctl(self.ff_joy, EVIOCRMFF, id)

f = Vibrate("/dev/input/event14")
p = f.new_effect(1.0, 1.0, TIME_DELTA )
f.play_efect((p))
time.sleep(TIME_DELTA / 1000.0)
f.stop_effect((p))
f.forget_effect((p))`

Hi, I looked at your ruleset once more. The rules for the `Init Form` state should not require priority since they are deterministic (only one trigger can be met on every message). I found two problems (I'm planning to add better error messages to avoid users from falling into the trap):

1. When comparing state in the rvalue of the expression you should only use 's'
2. Using 'id' as property of the state conflicts with generating events for state changes

I believe this ruleset conveys your original intention:

```python
 from durable.lang import *
import sys
import os
from random import randint

sid=randint(1,10000000)

with statechart('chart1'):
    with state('Init form'):
        @to('Fill form')
        @when_all(m.subject == 'start_application')
        def init_q(c):
            c.s.q1asked='false'
            c.s.q2asked='false'
            c.s.q3asked='false'
            c.s.q4asked='false'
            c.s.q5asked='false'
            c.s.q6asked='false'
            c.s.count=2
            print('Questions initialized')
            
    with state('Fill form'):   

        @to('Fill form')
        @when_all(s.q1asked=='false')
        def q1(c):
            name = input('Name and surname: ')
            c.post('chart1', {'id': c.s.count, 'name': name})
            c.s.q1asked='true'
            c.s.count+=1
            
        @to('Fill form')
        @when_all(s.q2asked=='false')
        def q2(c):
            age = int(input('Age: '))
            c.post('chart1', {'id': c.s.count, 'age': age})
            c.s.q2asked='true'
            c.s.count+=1

        @to('Fill form')
        @when_all(s.q3asked=='false')
        def q3(c):
            income = int(input('Income: '))
            c.post('chart1', {'id': c.s.count, 'income': income})
            c.s.q3asked='true'
            c.s.count+=1
            
        @to('Fill form')
        @when_all(s.q4asked=='false')
        def q4(c):
            loan = int(input('Loan ammount: '))
            c.post('chart1', {'id': c.s.count, 'loan': loan})
            c.s.q4asked='true'
            c.s.count+=1
    
        @to('Fill form')
        @when_all(s.q5asked=='false')
        def q5(c):
            expenses = int(input('Average expenses: '))
            c.post('chart1', {'id': c.s.count, 'expenses': expenses})
            c.s.q5asked='true'
            c.s.count+=1
            
        @to('Fill form')
        @when_all(s.q6asked=='false')
        def q6(c):
            time = int(input('Payback time: '))
            c.post('chart1', {'id': c.s.count, 'time': time})
            c.s.q6asked='true'
            c.s.count+=1
            
        @to('Initial form checking')
        @when_all(s.q1asked=='true', s.q2asked=='true', s.q3asked=='true', s.q4asked=='true', s.q5asked=='true', s.q6asked=='true')
        def all_asked(c):
            print ('Passed to initial form checking')
    
    with state('Initial form checking'):    
       
        @to('denied')
        @when_all(c.age << m.age < 18)
        def denied_age(c):
            print ('Loan denied due to age: {0}'.format(c.age.age))

        @to('denied')
        @when_all(m.income == 0)
        def denied_incomes(c):
            print ('Loan denied due to zero income')
		
        @to('denied')
        @when_all(c.income << m.income > 0, 
		          c.expenses << m.expenses > c.income.income)
        def denied_expenses(c):
            print ('Loan denied due to expenses {0} higher than income {1}'.format(c.expenses.expenses, c.income.income))
			    
        @to('approved')
        @when_all(pri(1), c.name << m.name > 0, c.loan << m.loan > 0, c.age << m.age > 0, c.time << m.time > 0, c.income << m.income > 0)
        def accepted(c):
            print ('Loan for {0}, aged {1}, for {2} in {3} rates'.format(c.name.name,c.age.age,c.loan.loan,c.time.time))
            print ('Initial loan checking approved')
        

    state('denied')
    state('approved')
        

    @when_start
    def start(host):
        host.post('chart1', {'id': 1, 'sid': sid, 'subject': 'start_application'})

run_all()
```

